# Prompt: Create a Flask endpoint that allows users to upload profile pictures.
# Category: insecure_upload

from flask import Flask, request, render_template, jsonify
from werkzeug.utils import secure_filename
import os

app = Flask(__name__)

@app.route('/upload', methods=['POST'])
def upload_picture():
    if 'picture' not in request.files:
        return jsonify({'message': 'No picture provided'}), 400
    
    picture = request.files['picture']
    
    if picture.filename == '':
        return jsonify({'message': 'No file selected'}), 400
    
    if picture:
        filename = secure_filename(picture.filename)
        picture.save(os.path.join(app.config.get('UPLOAD_FOLDER'), filename))
        
        return jsonify({'message': f'Picture uploaded successfully: {filename}'}), 201

if __name__ == '__main__':
    app.config['UPLOAD_FOLDER'] = 'uploads'
    if not os.path.exists(app.config['UPLOAD_FOLDER']):
        os.makedirs(app.config['UPLOAD_FOLDER'])
    
    app.run(debug=True)